import React, { useMemo, useRef } from "react";
import { AbsoluteFill, useCurrentFrame, useVideoConfig, interpolate, spring, Easing, Sequence } from "remotion";
import { Canvas, useFrame } from "@react-three/fiber";
import { Environment, Float, PerspectiveCamera, Stars } from "@react-three/drei";
import * as THREE from "three";
import { SafeArea, Subtitle } from "../components";
import { useTheme } from "../contexts/ThemeContext";

// ------------------------------------------------------------------
// 3D Component: Magma Simulation (Right Panel)
// ------------------------------------------------------------------

const MagmaParticles = ({ speed = 1 }) => {
  const count = 100;
  const mesh = useRef<THREE.InstancedMesh>(null);
  const lightRef = useRef<THREE.PointLight>(null);

  // Generate initial random positions
  const particles = useMemo(() => {
    const temp = [];
    for (let i = 0; i < count; i++) {
      const x = (Math.random() - 0.5) * 2; // -1 to 1
      const y = (Math.random() - 0.5) * 10; // -5 to 5
      const z = (Math.random() - 0.5) * 2; // -1 to 1
      const scale = Math.random() * 0.2 + 0.05;
      const speedOffset = Math.random() * 0.5 + 0.5;
      temp.push({ x, y, z, scale, speedOffset });
    }
    return temp;
  }, []);

  const dummy = new THREE.Object3D();

  useFrame((state) => {
    if (!mesh.current) return;

    const time = state.clock.getElapsedTime();

    particles.forEach((particle, i) => {
      // Move particles up
      let y = particle.y + time * particle.speedOffset * speed;
      // Reset if too high (looping effect)
      if (y > 5) {
        y = -5 + (y % 10);
      }

      // Wiggle
      const x = particle.x + Math.sin(time * 2 + i) * 0.1;

      dummy.position.set(x, y, particle.z);
      dummy.scale.setScalar(particle.scale);
      dummy.updateMatrix();
      mesh.current!.setMatrixAt(i, dummy.matrix);
    });
    mesh.current.instanceMatrix.needsUpdate = true;

    // Pulse light
    if (lightRef.current) {
      lightRef.current.intensity = 2 + Math.sin(time * 5) * 0.5;
    }
  });

  return (
    <group>
      <instancedMesh ref={mesh} args={[undefined, undefined, count]}>
        <sphereGeometry args={[1, 16, 16]} />
        <meshStandardMaterial 
          color="#FF4500" 
          emissive="#FF0000" 
          emissiveIntensity={2} 
          roughness={0.4} 
        />
      </instancedMesh>
      <pointLight ref={lightRef} position={[0, 0, 0]} color="#FFD700" distance={10} decay={2} />
    </group>
  );
};

const MagmaConduit = () => {
  return (
    <group>
      {/* The Conduit Tube */}
      <mesh position={[0, 0, 0]}>
        <cylinderGeometry args={[1.2, 1.5, 12, 32, 1, true]} />
        <meshStandardMaterial 
          color="#330000" 
          side={THREE.DoubleSide} 
          transparent 
          opacity={0.3}
          wireframe
        />
      </mesh>
      {/* Magma Flow Core */}
      <MagmaParticles speed={2} />
    </group>
  );
};

// ------------------------------------------------------------------
// 2D Component: Volcano Anatomy SVG (Left Panel)
// ------------------------------------------------------------------

const VolcanoSchematic = ({ showAnnotations, progress }: { showAnnotations: boolean, progress: number }) => {
  const theme = useTheme();

  // Simple SVG drawing of a volcano cross-section
  return (
    <div style={{ position: 'relative', width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <svg width="500" height="500" viewBox="0 0 500 500" style={{ overflow: 'visible' }}>
        <defs>
          <linearGradient id="rockGradient" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="#2d2d2d" />
            <stop offset="100%" stopColor="#4a4a4a" />
          </linearGradient>
          <linearGradient id="magmaGradient" x1="0%" y1="100%" x2="0%" y2="0%">
            <stop offset="0%" stopColor="#FF4500" />
            <stop offset="100%" stopColor="#FFD700" />
          </linearGradient>
        </defs>

        {/* Volcano Cone */}
        <path 
          d="M 50 400 L 200 150 L 230 200 L 270 200 L 300 150 L 450 400 Z" 
          fill="url(#rockGradient)" 
          stroke="#666" 
          strokeWidth="2"
        />

        {/* Magma Chamber */}
        <ellipse cx="250" cy="420" rx="80" ry="50" fill="url(#magmaGradient)" opacity={0.8} />

        {/* Conduit */}
        <path 
          d="M 230 400 L 230 200 L 270 200 L 270 400 Z" 
          fill="url(#magmaGradient)" 
          opacity={0.9}
        />

        {/* Crater */}
        <path 
          d="M 200 150 L 230 200 L 270 200 L 300 150" 
          fill="none" 
          stroke="#1a1a1a" 
          strokeWidth="3"
        />
      </svg>

      {/* Annotations Layer */}
      {showAnnotations && (
        <>
          <Annotation x="50%" y="85%" label="岩浆房 (Magma Chamber)" delay={0} progress={progress} />
          <Annotation x="50%" y="55%" label="火山通道 (Conduit)" delay={1} progress={progress} />
          <Annotation x="50%" y="30%" label="火山口 (Crater)" delay={2} progress={progress} />
          <Annotation x="75%" y="60%" label="火山锥 (Cone)" delay={3} progress={progress} />
        </>
      )}
    </div>
  );
};

const Annotation = ({ x, y, label, delay, progress }: { x: string, y: string, label: string, delay: number, progress: number }) => {
  const theme = useTheme();

  // Calculate local opacity based on progress (assuming progress 0-4 covers the sequence)
  // Each item takes 0.5s to fade in
  const start = delay;
  const end = delay + 0.5;
  const opacity = Math.min(Math.max((progress - start) / (end - start), 0), 1);

  if (opacity <= 0) return null;

  return (
    <div style={{
      position: 'absolute',
      left: x,
      top: y,
      transform: 'translate(-50%, -50%)',
      opacity,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      gap: 8
    }}>
      <div style={{ width: 12, height: 12, borderRadius: '50%', background: '#FFD700', boxShadow: '0 0 10px #FFD700' }} />
      <div style={{
        background: 'rgba(0,0,0,0.8)',
        padding: '8px 16px',
        borderRadius: 8,
        border: '1px solid rgba(255,255,255,0.2)',
        color: 'white',
        fontFamily: theme.fonts.body,
        fontSize: 18,
        whiteSpace: 'nowrap'
      }}>
        {label}
      </div>
    </div>
  );
};

