        </svg>
      </AbsoluteFill>

      <SafeArea padding={60} paddingBottom={160} style={{ zIndex: 1 }}>
        <div style={{ 
          display: 'flex', 
          width: '100%', 
          height: '100%', 
          gap: 40 
        }}>

          {/* Left Panel: Anatomy */}
          <div style={{ 
            flex: 1, 
            transform: `translateX(${anatomyX}px)`, 
            opacity: anatomyOpacity,
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
            background: 'rgba(0,0,0,0.3)',
